     7→import { addCollections, getCollections } from '../../../API/Api';
     8→import { useAuth } from '../../Context/useAuth';
     9→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
    10→import CollectionCards from './CollectionCards';
    11→import { BarLoader } from 'react-spinners';
    12→
    13→const Collections = () =>{
    14→    const {user, session} = useAuth();
    15→    const queryClient = useQueryClient();
    16→
    17→    const [showCollectionEditor, setShowCollectionEditor] = useState(false);
    18→    const [showOlderPost, setShowOlderPost] = useState(false)
    19→    const [olderPost, setOlderPost] = useState([]);
    20→    const [savingCollection, setSavingCollection] = useState(false);
    21→
    22→    const [collectionTitle, setCollectionTitle] = useState('');
    23→    const [collectionDescription, setCollectionDescription] = useState('');
    24→
    25→    const isDisabled = !collectionDescription || !collectionTitle || savingCollection;
    26→
    27→    const handleClickBack = (e) =>{
    28→        e.stopPropagation();
    29→        window.history.back();
    30→    }
    31→
    32→    const handleClickSaveCollection = async(e) =>{
    33→        e.stopPropagation();
    34→        // console.log(collectionDescription, collectionTitle)
    35→        console.log('jornalids', journalIds)
    36→        setSavingCollection(true);
    37→        const formdata = new FormData();
    38→
    39→        // journalIds, title, description
    40→        formdata.append('journalIds', journalIds)
    41→        formdata.append('title', collectionTitle)
    42→        formdata.append('description', collectionDescription)
    43→
    44→        try {
    45→            const message = await addCollections(session?.access_token, formdata)
    46→            if(message){
    47→                console.log(message)
    48→                setCollectionDescription('')
    49→                setCollectionTitle('')
    50→                setOlderPost([])
    51→                setSavingCollection(false)           
    52→                setShowCollectionEditor(false)
    53→            }
    54→        } catch (error) {
    55→                setCollectionDescription('')
    56→                setCollectionTitle('')
    57→                setOlderPost([])
    58→                setSavingCollection(false)
    59→                setShowCollectionEditor(false)
    60→                throw new Error('error adding collections',error)
    61→
    62→        } finally {
    63→            queryClient.invalidateQueries(['getCollections', user?.userData?.[0].id]);
    64→        }
    65→    }
    66→
    67→    const handleClickShowCollectionEditor = (e) =>{
    68→        e.stopPropagation();
    69→        console.log('clicks')
    70→        setShowCollectionEditor(true);
    71→    }
    72→
    73→    const handleClickShowOlderPost = (e) =>{
    74→        e.stopPropagation();
    75→        setShowOlderPost(true)
    76→    }
    77→    const handleCloseShowOlderPost = () =>{
    78→        setShowOlderPost(false)
    79→    }
    80→
    81→    const handleClickSaveSelectedContent = (data) =>{
    82→        // console.log(data)
    83→        const postArray = Array.from(data.values());
    84→        setOlderPost(postArray);
    85→        setShowOlderPost(false)
    86→    }
    87→
    88→    useEffect(() =>{
    89→        console.log(olderPost)
    90→    }, [olderPost])
    91→
    92→    useEffect(() =>{
    93→        const handleClickOutside = (e) =>{
    94→            if(showCollectionEditor && !e.target.closest('.collection-editor')){
    95→                setShowCollectionEditor(false)
    96→                setCollectionDescription('')
    97→                setCollectionTitle('')
    98→                setOlderPost([])
    99→            }
   100→        }
   101→
   102→        document.addEventListener('click', handleClickOutside);
   103→
   104→        return() =>{
   105→            document.removeEventListener('click', handleClickOutside)
   106→        }
   107→    }, [showCollectionEditor])
   108→
   109→    const journals = olderPost?.flatMap((journal) => journal) || [];
   110→    const journalIds = olderPost?.flatMap((journal) => journal.id) || [];
   111→
   112→    return(
   113→        <>
   114→        <div className='collection-header'>
   115→            <div onClick={(e) => handleClickBack(e)} className='back-button'>
