   144→                    <g id="SVGRepo_bgCarrier" strokeWidth="0"/>
   145→                    <g id="SVGRepo_tracerCarrier" strokeLinecap="round" strokeLinejoin="round"/>
   146→                    <g id="SVGRepo_iconCarrier">
