   148→                        <path id="secondary" d="M10,14a1,1,0,0,1-1-1V11H7A1,1,0,0,1,7,9H9V7a1,1,0,0,1,2,0V9h2a1,1,0,0,1,0,2H11v2A1,1,0,0,1,10,14Z" style={{fill: '#ffffff'}}/>
   149→                    </g>
   150→                </svg>
