   152→            </div>
   153→        </div>
   154→
   155→        <CollectionCards/>
   156→
   157→
   158→
   159→        {showOlderPost && (
   160→            <OlderPost onClose={handleCloseShowOlderPost} onSave={handleClickSaveSelectedContent}/>
   161→        )}
   162→
   163→        {showCollectionEditor && (
   164→            <AnimatePresence>
   165→            <motion.div
   166→            initial={{opacity: 0, scale: 0}}
   167→            animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.1}}}
   168→            exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.1}}}
   169→            className='collection-editor'
   170→            >
   171→                {savingCollection && (
   172→                    <div className='is-saving-collections'>
   173→                        <BarLoader loading={savingCollection} width={'100%'}/>
   174→                    </div>
   175→                    
   176→                )}
   177→
   178→                <div className='collection-input-name'>
   179→                    <div className='field-name'>
   180→                        Collection name:
   181→                    </div>
   182→                    <div className='input-name-container'>
   183→                        <input maxLength={50} value={collectionTitle} onChange={(e) => setCollectionTitle(e.target.value)} className='input-name-collection' type="text" placeholder='Collection name'/>
   184→                        <p style={collectionTitle?.length > 49 ? {color: 'red'} : {}} className='collection-title-text-limit'>{collectionTitle.length} / 50</p>
   185→                    </div>
   186→                </div>
   187→                <div className='collection-input-description'>
   188→                    <div className='field-name'>
   189→                        Add description:
   190→                    </div>
   191→                    <div className='input-description-container'>
   192→                        <textarea value={collectionDescription} onChange={(e) => setCollectionDescription(e.target.value)} placeholder='collection description' maxLength={550} name="description" id="collection-description" className='collection-description'></textarea>
   193→                        <p style={collectionDescription.length > 549 ? {color: 'red'} : {}} className='collection-description-limit'>{collectionDescription.length} / 550</p>
   194→                    </div>
   195→
   196→                    <div className='create-or-add-container'>
   197→                        <div onClick={(e) => handleClickShowOlderPost(e)} className='add-older-post-container'>
   198→                            Add older Post
   199→                        </div>
   200→                    </div>
   201→                </div>
   202→            
   203→
   204→                <div className='journal-list'>
   205→                    {journals?.map((journal) => {
   206→                        const parsedContent = ParseContent(journal?.content);
   207→
   208→                        return(
   209→                            <div className='collection-cards-selected-old-post' key={journal?.id}>
   210→                                <div className='journal-title'>
   211→                                    {journal?.title?.length > 10 ? `${journal?.title?.substring(0, 9)}...` : journal?.title}
   212→                                </div>
   213→                                <div className='journal-text'>
   214→                                    {parsedContent?.slicedText}
   215→                                </div>
   216→                            </div>
   217→                        )
   218→                        
   219→                    })}
   220→                </div>
   221→                 
   222→                <button disabled={isDisabled} onClick={(e) => handleClickSaveCollection(e, journalIds)} className={isDisabled ? 'save-collection-container-disabled' : 'save-collection-container'}>
   223→                    <div className='save-collection-bttn'>
   224→                        Save Collection
   225→                    </div>
   226→                </button>
   227→
   228→            </motion.div>
   229→            </AnimatePresence>
   230→        )}   
   231→        </>
   232→    )
   233→}
   234→
   235→export default Collections;

